    // Example array
    vector<int> arr = {3, 10, 5, 25, 2, 8};

    // Display the given array
    cout << "Given Array: ";
    for (int i = 0; i < arr.size(); i++) {
        cout << arr[i] << " ";
    }
    cout << endl;

