// Class containing the solution logic
class Solution {
    maxXorQueries(arr, queries) {
        // Sort array
        arr.sort((a, b) => a - b);

        // Store queries with index
        let offlineQueries = queries.map((q, idx) => [q[1], q[0], idx]);

        // Sort queries based on m
        offlineQueries.sort((a, b) => a[0] - b[0]);

        // Result array
        let ans = Array(queries.length).fill(0);

        // Trie object
        let trie = new Trie();

        // Array pointer
        let i = 0;
        let n = arr.length;

        // Process queries
        for (let [m, x, idx] of offlineQueries) {
            while (i < n && arr[i] <= m) {
                trie.insert(arr[i]);
                i++;
            }
            if (i !== 0) {
                ans[idx] = trie.findMax(x);
            } else {
                ans[idx] = -1;
            }
        }
        return ans;
    }
}

